define("mod_videoassessment/record",["mod_videoassessment/media","mod_videoassessment/uploader"],(function(media,uploader){var MAX_LENGTH_MS=12e4;function init(){var btnStart=document.querySelector("#btn-start-recording"),btnPause=document.querySelector("#btn-pause-recording"),recorder,stream,autoStopTimer=null;function clearAutoStop(){if(autoStopTimer!==null){clearTimeout(autoStopTimer);autoStopTimer=null;}}function finishRecording(){if(!recorder){return;}clearAutoStop();recorder.stopRecording(function(){var blob=recorder.getBlob();uploader.upload(blob,recorder.mimeType);});}btnStart.addEventListener("click",function(){if(recorder&&recorder.getState()==="recording"){finishRecording();return;}media.captureUserMedia(function(userStream){stream=userStream;recorder=new RecordRTC(stream,{type:"video",mimeType:"video/webm",disableLogs:false});recorder.startRecording();btnPause.style.display="";btnStart.textContent=M.str.videoassessment.stoprecording;clearAutoStop();autoStopTimer=window.setTimeout(finishRecording,MAX_LENGTH_MS);},function(err){window.alert(M.str.videoassessment.errorcapturingmedia+" "+err.message);});});btnPause.addEventListener("click",function(){if(!recorder){return;}if(btnPause.textContent===M.str.videoassessment.pause){recorder.pauseRecording();btnPause.textContent=M.str.videoassessment.resumerecording;}else{recorder.resumeRecording();btnPause.textContent=M.str.videoassessment.pause;}});}return{reCord:init};}));

